{
  "sentences": [
    {
      "text": "對了，你最近有去哪裡玩嗎？",
      "pinyin": "Duìle, nǐ zuìjìn yǒu qù nǎlǐ wán ma?",
      "pinyin_numeric": "dui4le0, ni3 zui4jin4 you3 qu4 na3li3 wan2 ma0",
      "translation_en": "By the way, have you been anywhere fun recently?",
      "translation_ko": "그런데, 요즘 어디 놀러 다녔어요?"
    },
    {
      "text": "說到興趣，你覺得怎麼樣？",
      "pinyin": "Shuō dào xìngqù, nǐ juéde zěnmeyàng?",
      "pinyin_numeric": "shuo1 dao4 xing4qu4, ni3 jue2de0 zen3me0yang4",
      "translation_en": "Speaking of hobbies, what do you think?",
      "translation_ko": "취미에 관해서 말하자면, 어떻게 생각하세요?"
    },
    {
      "text": "對了，你放假的時候喜歡做什麼？",
      "pinyin": "Duìle, nǐ fàngjià de shíhou xǐhuān zuò shénme?",
      "pinyin_numeric": "dui4le0, ni3 fang4jia4 de0 shi2hou0 xi3huan1 zuo4 shen2me0",
      "translation_en": "By the way, what do you like to do on your days off?",
      "translation_ko": "그런데, 쉬는 날에는 뭐 하는 걸 좋아하세요?"
    },
    {
      "pinyin": "Shuō dào zhōumò, nǐ yǒu shénme dǎsuàn ma?",
      "pinyin_numeric": "shuo1 dao4 zhou1mo4, ni3 you3 shen2me0 da3suan4 ma0",
      "text": "說到週末，你有什麼打算嗎？",
      "translation_en": "Speaking of the weekend, do you have any plans?",
      "translation_ko": "주말에 관해서 말하자면, 무슨 계획이 있으세요?"
    },
    {
      "pinyin": "Duìle, nǐ juéde zhège dìfang zěnmeyàng?",
      "pinyin_numeric": "dui4le0, ni3 jue2de0 zhe4ge0 di4fang0 zen3me0yang4",
      "text": "對了，你覺得這個地方怎麼樣？",
      "translation_en": "By the way, what do you think of this place?",
      "translation_ko": "그런데, 이 장소는 어떠세요?"
    },
    {
      "pinyin": "Shuō dào chī de, nǐ yǒu tuījiàn ma?",
      "pinyin_numeric": "shuo1 dao4 chi1 de0, ni3 you3 tui1jian4 ma0",
      "text": "說到吃的，你有推薦嗎？",
      "translation_en": "Speaking of food, do you have any recommendations?",
      "translation_ko": "음식에 관해서 말하자면, 추천해 주실 게 있나요?"
    },
    {
      "pinyin": "Duìle, nǐ yě xǐhuān kàn diànyǐng ma?",
      "pinyin_numeric": "dui4le0, ni3 ye3 xi3huan1 kan4 dian4ying3 ma0",
      "text": "對了，你也喜歡看電影嗎？",
      "translation_en": "By the way, do you also like watching movies?",
      "translation_ko": "그런데, 영화 보는 것도 좋아하세요?"
    },
    {
      "pinyin": "Shuō dào lǚxíng, nǐ qùguò nǎlǐ?",
      "pinyin_numeric": "shuo1 dao4 lü3xing2, ni3 qu4guo4 na3li3",
      "text": "說到旅行，你去過哪裡？",
      "translation_en": "Speaking of travel, where have you been?",
      "translation_ko": "여행에 관해서 말하자면, 어디 가 보셨어요?"
    },
    {
      "pinyin": "Duìle, nǐ zuìjìn máng ma?",
      "pinyin_numeric": "dui4le0, ni3 zui4jin4 mang2 ma0",
      "text": "對了，你最近忙嗎？",
      "translation_en": "By the way, have you been busy lately?",
      "translation_ko": "그런데, 요즘 바쁘세요?"
    },
    {
      "pinyin": "Shuō dào gōngzuò, nǐ juéde zěnmeyàng?",
      "pinyin_numeric": "shuo1 dao4 gong1zuo4, ni3 jue2de0 zen3me0yang4",
      "text": "說到工作，你覺得怎麼樣？",
      "translation_en": "Speaking of work, what do you think?",
      "translation_ko": "일에 관해서 말하자면, 어떻게 생각하세요?"
    }
  ]
}
